typedef struct{uint64_t s;} rng;
static int rb(void*ctx,uint8_t*out,size_t n){rng*r=ctx;for(size_t i=0;i<n;i++){r->s=r->s*6364136223846793005ULL+1442695040888963407ULL;out[i]=(uint8_t)(r->s>>56);}return 0;}
static int failrb(void*ctx,uint8_t*out,size_t n){(void)ctx;(void)out;(void)n;return -9;}
static int exhaustive_u16(const sdat_table*t){const uint16_t*p=t->pmf,*c=t->thresholds; uint32_t h[32]={0}; for(uint32_t x=0;x<t->denominator_u64;x++) h[online_lookup_u16((uint16_t)x,c,t->threshold_count)]++; for(size_t i=0;i<t->mass_count;i++) if(h[i]!=p[i]) return (int)i+1; return 0;}
static int cross_original(const sdat_table*t,size_t n){uint32_t*a=calloc(n,sizeof*a),*b=calloc(n,sizeof*b); if(!a||!b)return 90; rng r1={7},r2={7}; sdat_stats s1={0},s2={0}; if(original_cdt_ref_sample_batch(t,rb,&r1,a,n,&s1))return 91; online_avx2_stats_reset(); if(original_cdt_avx2_sample_batch(t,rb,&r2,b,n,&s2))return 92; int rc=memcmp(a,b,n*sizeof*a)?93:0; if(!rc&&(s1.attempts!=s2.attempts||s1.rejections!=s2.rejections))rc=94; free(a);free(b);return rc;}
static int cross_falcon(size_t n){uint32_t*a=calloc(n,sizeof*a),*b=calloc(n,sizeof*b); if(!a||!b)return 80; rng r1={11},r2={11}; sdat_stats s1={0},s2={0}; if(sda_cdt_ref_sample_batch(&sda_table_falcon_base,rb,&r1,a,n,&s1))return 81; online_avx2_stats_reset(); if(sda_cdt_avx2_sample_batch(&sda_table_falcon_base,rb,&r2,b,n,&s2))return 82; int rc=memcmp(a,b,n*sizeof*a)?83:0; if(!rc&&(s1.attempts!=s2.attempts||s1.rejections!=s2.rejections))rc=84; free(a);free(b);return rc;}
int main(void){ if(online_table_validate(&original_cdt_table_frodo640)||online_table_validate(&original_cdt_table_frodo976)||online_table_validate(&original_cdt_table_frodo1344)) return 1; if(online_table_validate(&sda_table_falcon_base)) return 2; if(sda_table_frodo640.available||sda_table_frodo976.available||sda_table_frodo1344.available) return 3; if(exhaustive_u16(&original_cdt_table_frodo640)||exhaustive_u16(&original_cdt_table_frodo976)||exhaustive_u16(&original_cdt_table_frodo1344)) return 4; uint8_t le[9]={0xff,0xff,0xff,0xff,0xff,0xff,0xff,0xff,0x7f}; sdat_u72 u=sdat_u72_from_le9(le); if(u.hi!=0x7f||u.lo!=UINT64_MAX) return 5; const sdat_u72 *th=(const sdat_u72*)sda_table_falcon_base.thresholds; if(online_lookup_u72((sdat_u72){0,0},th,18)!=0) return 6; if(online_lookup_u72(th[0],th,18)!=1) return 7; if(online_lookup_u72((sdat_u72){10215721069833441391ULL,254},th,18)!=18) return 8; rng rf={1}; uint32_t x; if(sda_cdt_ref_sample(&sda_table_falcon_base,failrb,0,&x,0)!=-2)return 9; if(sda_cdt_ref_sample(&sda_table_frodo640,rb,&rf,&x,0)==0)return 10; if(sdat_avx2_cpu_supported()){ if(cross_original(&original_cdt_table_frodo640,1000000))return 11; if(cross_original(&original_cdt_table_frodo976,1000000))return 12; if(cross_original(&original_cdt_table_frodo1344,1000000))return 13; if(cross_falcon(1000000))return 14; } puts("online SDA_CDT tests passed; Frodo SDAT PMF/cumulative unresolved"); return 0; }
